#!/usr/bin/env bash
set -euo pipefail
cd "$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"
device=cuda;steps=4096;batch=4;experiment=all;overwrite=0;dry=0;root=runs/channel_free_feasibility
while (($#));do case "$1" in --device)device="$2";shift 2;;--steps)steps="$2";shift 2;;--batch-size)batch="$2";shift 2;;--experiment)experiment="$2";shift 2;;--overwrite)overwrite=1;shift;;--dry-run)dry=1;shift;;*)echo "unknown argument: $1" >&2;exit 2;;esac;done
run_train(){ local mode="$1";local name="$2";local out="$root/$name";local cmd=(python train_channel_free_feasibility.py --config configs/channel_free_feasibility.yaml --experiment "$mode" --output-dir "$out" --device "$device" --steps "$steps" --batch-size "$batch" --allow-long-run);((overwrite))&&cmd+=(--overwrite);if ((dry));then printf '%q ' "${cmd[@]}";echo;return;fi;[[ ! -e "$out"||$overwrite -eq 1 ]]||{ echo "refusing existing output directory: $out" >&2;return 1;};mkdir -p "$root";local log="${out}.run.log";"${cmd[@]}" 2>&1|tee "$log";mv "$log" "$out/run.log";}
run_eval(){ local out="$root/final_comparison";local cmd=(python eval_channel_free_feasibility.py --config configs/channel_free_feasibility.yaml --experiment-a-best-latent "$root/experiment_a_latent_only/best_latent.pt" --experiment-a-best-waveform "$root/experiment_a_latent_only/best_waveform.pt" --experiment-b-best-waveform "$root/experiment_b_waveform_connected/best_waveform.pt" --output-dir "$out" --device "$device" --samples 64 --allow-long-run);[[ -f "$root/experiment_c_large_bottleneck/best_waveform.pt" ]]&&cmd+=(--experiment-c-best-waveform "$root/experiment_c_large_bottleneck/best_waveform.pt");((overwrite))&&cmd+=(--overwrite);if ((dry));then printf '%q ' "${cmd[@]}";echo;return;fi;[[ ! -e "$out"||$overwrite -eq 1 ]]||{ echo "refusing existing output directory: $out" >&2;return 1;};local log="${out}.run.log";"${cmd[@]}" 2>&1|tee "$log";mv "$log" "$out/run.log";}
case "$experiment" in a)run_train a experiment_a_latent_only;;b)run_train b experiment_b_waveform_connected;;c)run_train c experiment_c_large_bottleneck;;eval)run_eval;;all)run_train a experiment_a_latent_only;run_train b experiment_b_waveform_connected;run_eval;;*)echo "--experiment must be a, b, c, eval, or all" >&2;exit 2;;esac
